// Package scalars provides hand-rolled types for Caido GraphQL scalars and
// inputs that need a stable Go API independent of generated code.
//
// HTTPQLInput is the input-object form of the HTTPQL filter (post Caido
// 0.56). It accepts a raw HTTPQL query string in the `code` field, exactly
// as the operator would type it in the Caido UI search bar.
package scalars

// HTTPQLInput mirrors the GraphQL `input HTTPQLInput { code: String! }`
// shape used as a filter argument in queries like `requests`,
// `interceptEntries`, `automateEntries`, etc.
type HTTPQLInput struct {
	Code string `json:"code"`
}

// NewHTTPQLInput returns a pointer-input wrapper for a non-empty query
// string. Returns nil for an empty string so the caller can pass it
// directly into pointer-typed `*HTTPQLInput` parameters generated by
// genqlient (nil ⇒ omit the variable).
func NewHTTPQLInput(query string) *HTTPQLInput {
	if query == "" {
		return nil
	}
	return &HTTPQLInput{Code: query}
}
